SELECT wl.id, wl.production_line_id AS productionLineId, pl.line_name AS productionLineName, wl.area_code AS areaCode, wl.location_code AS locationCode, wl.keeper_username AS keeperUsername, wl.keeper_real_name AS keeperRealName, wl.creator_id AS creatorId, wl.created_at AS createdAt, wl.updated_at AS updatedAt FROM warehouse_location wl LEFT JOIN production_line pl ON wl.production_line_id = pl.id
AND wl.creator_id = #{creatorId}
AND wl.production_line_id = #{productionLineId}
ORDER BY wl.id DESC

SELECT id, production_line_id AS productionLineId, area_code AS areaCode, location_code AS locationCode
FROM warehouse_location
WHERE production_line_id = #{productionLineId}
  AND area_code = #{areaCode}
  AND location_code = #{locationCode}

      AND creator_id = #{creatorId}


      AND id != #{id}

